import os
import gzip
import json
import base64
import anthropic
from fastapi import FastAPI, HTTPException
from fastapi.staticfiles import StaticFiles
from fastapi.middleware.cors import CORSMiddleware
from fastapi.responses import JSONResponse
from pydantic import BaseModel
from typing import Optional, Any

app = FastAPI(title="Ecosistema IA - 60 Especialistas")

app.add_middleware(
    CORSMiddleware,
    allow_origins=["*"],
    allow_credentials=True,
    allow_methods=["*"],
    allow_headers=["*"],
)

_client = None

def get_client():
    global _client
    if _client is None:
        api_key = os.environ.get("ANTHROPIC_API_KEY")
        if not api_key:
            raise RuntimeError("ANTHROPIC_API_KEY no configurada en variables de entorno")
        _client = anthropic.Anthropic(api_key=api_key)
    return _client


class ChatRequest(BaseModel):
    messages: list[Any]
    system: Optional[str] = ""
    max_tokens: int = 800
    model: str = "claude-haiku-4-5-20251001"


@app.post("/api/chat")
async def chat(req: ChatRequest):
    try:
        client = get_client()
        kwargs = dict(
            model=req.model,
            max_tokens=min(req.max_tokens, 2000),
            messages=req.messages,
        )
        if req.system:
            kwargs["system"] = req.system

        response = client.messages.create(**kwargs)
        return {"text": response.content[0].text}

    except anthropic.AuthenticationError:
        raise HTTPException(status_code=401, detail="API key de Anthropic invalida")
    except anthropic.RateLimitError:
        raise HTTPException(status_code=429, detail="Limite de velocidad alcanzado")
    except anthropic.BadRequestError as e:
        raise HTTPException(status_code=400, detail=str(e))
    except Exception as e:
        raise HTTPException(status_code=500, detail=str(e))


@app.get("/api/health")
async def health():
    key_set = bool(os.environ.get("ANTHROPIC_API_KEY"))
    return {"status": "ok", "api_key_configured": key_set}


# Specialists data (gzip-compressed, base64-encoded)
_SPECIALISTS_B64 = ""

_specialists_cache = None

@app.get("/api/specialists")
async def get_specialists():
    global _specialists_cache
    if _specialists_cache is None:
        compressed = base64.b64decode(_SPECIALISTS_B64)
        raw = gzip.decompress(compressed)
        _specialists_cache = json.loads(raw.decode("utf-8"))
    return JSONResponse(content=_specialists_cache)


# Serve static frontend (index.html = the app)
app.mount("/", StaticFiles(directory="static", html=True), name="static")
